class CallAlreadyActiveException(userId: String) :
    RuntimeException("이미 통화 중인 사용자입니다: $userId")

class CallSelfCallException :
    RuntimeException("자기 자신에게 통화를 걸 수 없습니다.")

class CallInvalidStatusTransitionException(from: String, to: String) :
    RuntimeException("잘못된 통화 상태 전환입니다: $from → $to")

class CallUnauthorizedException(userId: String, callId: String) :
