```kotlin
package com.maum.backend.service

import com.maum.backend.entity.call.CallEntity
import com.maum.backend.entity.call.CallStatus
import com.maum.backend.exception.CallAlreadyActiveException
import com.maum.backend.exception.CallInvalidStatusTransitionException
import com.maum.backend.exception.CallNotFoundException
import com.maum.backend.exception.CallSelfCallException
import com.maum.backend.exception.CallUnauthorizedException
import com.maum.backend.repository.call.CallRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import java.time.LocalDateTime

@Service
class CallService(
    private val callRepository: CallRepository,
) {

    /** 통화 요청 (PENDING 생성) */
    @Transactional
    fun initiateCall(callerId: String, receiverId: String): CallEntity {
        if (callerId == receiverId) {
            throw CallSelfCallException()
        }

        val activeStatus = CallStatus.ACTIVE.code
        val hasActiveCall = callRepository.findActiveCallByUserId(callerId, activeStatus).isNotEmpty()
            || callRepository.findActiveCallByUserId(receiverId, activeStatus).isNotEmpty()

        if (hasActiveCall) {
            throw CallAlreadyActiveException(callerId)
        }

        val call = CallEntity(
            callerId = callerId,
            receiverId = receiverId,
            status = CallStatus.PENDING.code,
        )
        return callRepository.save(call)
    }

    /** 통화 수락 (PENDING → ACTIVE) */
    @Transactional
    fun acceptCall(callId: String, userId: String): CallEntity {
        val call = findCallOrThrow(callId)

        if (call.receiverId != userId) {
            throw CallUnauthorizedException(userId, callId)
        }

        if (call.status != CallStatus.PENDING.code) {
            throw CallInvalidStatusTransitionException(
                CallStatus.fromCode(call.status).name,
                CallStatus.ACTIVE.name,
            )
        }

        call.status = CallStatus.ACTIVE.code
        call.startedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    /** 통화 거절 (PENDING → DECLINED) */
    @Transactional
    fun declineCall(callId: String, userId: String): CallEntity {
        val call = findCallOrThrow(callId)

        if (call.receiverId != userId) {
            throw CallUnauthorizedException(userId, callId)
        }

        if (call.status != CallStatus.PENDING.code) {
            throw CallInvalidStatusTransitionException(
                CallStatus.fromCode(call.status).name,
                CallStatus.DECLINED.name,
            )
        }

        call.status = CallStatus.DECLINED.code
        return callRepository.save(call)
    }

    /** 통화 종료 (ACTIVE → ENDED) */
    @Transactional
    fun endCall(callId: String, userId: String): CallEntity {
        val call = findCallOrThrow(callId)

        if (call.callerId != userId && call.receiverId != userId) {
            throw CallUnauthorizedException(userId, callId)
        }

        if (call.status != CallStatus.ACTIVE.code) {
            throw CallInvalidStatusTransitionException(
                CallStatus.fromCode(call.status).name,
                CallStatus.ENDED.name,
            )
        }

        val now = LocalDateTime.now()
        call.status = CallStatus.ENDED.code
        call.endedAt = now
        call.durationSeconds = call.startedAt
            ?.let { java.time.Duration.between(it, now).seconds }
            ?: 0L

        return callRepository.save(call)
    }

    /** 부재중 처리 (PENDING → MISSED) */
    @Transactional
    fun markAsMissed(callId: String): CallEntity {
        val call = findCallOrThrow(callId)

        if (call.status != CallStatus.PENDING.code) {
            throw CallInvalidStatusTransitionException(
                CallStatus.fromCode(call.status).name,
                CallStatus.MISSED.name,
            )
        }

        call.status = CallStatus.MISSED.code
        return callRepository.save(call)
    }

    /** 통화 조회 */
    @Transactional(readOnly = true)
    fun getCall(callId: String): CallEntity = findCallOrThrow(callId)

    /** 사용자의 통화 이력 조회 */
    @Transactional(readOnly = true)
    fun getCallHistory(userId: String): List<CallEntity> =
        callRepository.findByCallerIdOrReceiverId(userId, userId)

    private fun findCallOrThrow(callId: String): CallEntity =
        callRepository.findById(callId)
            .orElseThrow { CallNotFoundException(callId) }
}
```

