package com.maum.backend.service

import com.maum.backend.entity.call.CallEntity
import com.maum.backend.entity.call.CallStatus
import com.maum.backend.exception.CallAlreadyActiveException
import com.maum.backend.exception.CallInvalidStatusTransitionException
import com.maum.backend.exception.CallNotFoundException
import com.maum.backend.exception.CallSelfCallException
import com.maum.backend.exception.CallUnauthorizedException
import com.maum.backend.repository.call.CallRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.Mockito.`when`
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import java.time.LocalDateTime
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class CallServiceTest {

    @Mock
    private lateinit var callRepository: CallRepository

    @InjectMocks
    private lateinit var callService: CallService

    // ──────────────────────────────────────────────────────────────
    // initiateCall
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should create PENDING call when initiateCall is requested`() {
        // given
        val callerId = "user-A"
        val receiverId = "user-B"
        val savedCall = CallEntity(
            id = "call-1",
            callerId = callerId,
            receiverId = receiverId,
            status = CallStatus.PENDING.code,
        )

        `when`(callRepository.findActiveCallByUserId(callerId, CallStatus.ACTIVE.code))
            .thenReturn(emptyList())
        `when`(callRepository.findActiveCallByUserId(receiverId, CallStatus.ACTIVE.code))
            .thenReturn(emptyList())
        `when`(callRepository.save(any())).thenReturn(savedCall)

        // when
        val result = callService.initiateCall(callerId, receiverId)

        // then
        assertThat(result.callerId).isEqualTo(callerId)
        assertThat(result.receiverId).isEqualTo(receiverId)
        assertThat(result.status).isEqualTo(CallStatus.PENDING.code)
        verify(callRepository).save(any())
    }

    @Test
    fun `should throw CallSelfCallException when caller and receiver are the same`() {
        // given
        val userId = "user-A"

        // when & then
        assertThrows<CallSelfCallException> {
            callService.initiateCall(userId, userId)
        }
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw CallAlreadyActiveException when caller is already in an active call`() {
        // given
        val callerId = "user-A"
        val receiverId = "user-B"
        val activeCall = CallEntity(
            id = "call-existing",
            callerId = callerId,
            receiverId = "user-C",
            status = CallStatus.ACTIVE.code,
        )

        `when`(callRepository.findActiveCallByUserId(callerId, CallStatus.ACTIVE.code))
            .thenReturn(listOf(activeCall))

        // when & then
        assertThrows<CallAlreadyActiveException> {
            callService.initiateCall(callerId, receiverId)
        }
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw CallAlreadyActiveException when receiver is already in an active call`() {
        // given
        val callerId = "user-A"
        val receiverId = "user-B"
        val activeCall = CallEntity(
            id = "call-existing",
            callerId = "user-C",
            receiverId = receiverId,
            status = CallStatus.ACTIVE.code,
        )

        `when`(callRepository.findActiveCallByUserId(callerId, CallStatus.ACTIVE.code))
            .thenReturn(emptyList())
        `when`(callRepository.findActiveCallByUserId(receiverId, CallStatus.ACTIVE.code))
            .thenReturn(listOf(activeCall))

        // when & then
        assertThrows<CallAlreadyActiveException> {
            callService.initiateCall(callerId, receiverId)
        }
    }

    // ──────────────────────────────────────────────────────────────
    // acceptCall
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should transition call to ACTIVE when acceptCall is called by receiver`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val pendingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.PENDING.code,
        )
        val savedCall = pendingCall.apply {
            status = CallStatus.ACTIVE.code
            startedAt = LocalDateTime.now()
        }

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))
        `when`(callRepository.save(any())).thenReturn(savedCall)

        // when
        val result = callService.acceptCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ACTIVE.code)
        assertThat(result.startedAt).isNotNull
        verify(callRepository).save(pendingCall)
    }

    @Test
    fun `should throw CallUnauthorizedException when acceptCall is called by non-receiver`() {
        // given
        val callId = "call-1"
        val intruder = "user-X"
        val pendingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.PENDING.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))

        // when & then
        assertThrows<CallUnauthorizedException> {
            callService.acceptCall(callId, intruder)
        }
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw CallInvalidStatusTransitionException when acceptCall is called on ENDED call`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val endedCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.ENDED.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(endedCall))

        // when & then
        assertThrows<CallInvalidStatusTransitionException> {
            callService.acceptCall(callId, receiverId)
        }
    }

    @Test
    fun `should throw CallInvalidStatusTransitionException when acceptCall is called on DECLINED call`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val declinedCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.DECLINED.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(declinedCall))

        // when & then
        assertThrows<CallInvalidStatusTransitionException> {
            callService.acceptCall(callId, receiverId)
        }
    }

    // ──────────────────────────────────────────────────────────────
    // declineCall
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should transition call to DECLINED when declineCall is called by receiver`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val pendingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.PENDING.code,
        )
        val savedCall = pendingCall.apply { status = CallStatus.DECLINED.code }

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))
        `when`(callRepository.save(any())).thenReturn(savedCall)

        // when
        val result = callService.declineCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.DECLINED.code)
    }

    @Test
    fun `should throw CallUnauthorizedException when declineCall is called by non-receiver`() {
        // given
        val callId = "call-1"
        val intruder = "user-X"
        val pendingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
