import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.Mockito.`when`
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import java.time.LocalDateTime
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class CallServiceTest {

    @Mock
    private lateinit var callRepository: CallRepository

    @InjectMocks
    private lateinit var callService: CallService

    // ──────────────────────────────────────────────────────────────
    // initiateCall
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should create PENDING call when initiateCall is requested`() {
        // given
        val callerId = "user-A"
        val receiverId = "user-B"
        val savedCall = CallEntity(
            id = "call-1",
            callerId = callerId,
            receiverId = receiverId,
            status = CallStatus.PENDING.code,
        )

        `when`(callRepository.findActiveCallByUserId(callerId, CallStatus.ACTIVE.code))
            .thenReturn(emptyList())
        `when`(callRepository.findActiveCallByUserId(receiverId, CallStatus.ACTIVE.code))
            .thenReturn(emptyList())
        `when`(callRepository.save(any())).thenReturn(savedCall)

        // when
        val result = callService.initiateCall(callerId, receiverId)

        // then
        assertThat(result.callerId).isEqualTo(callerId)
        assertThat(result.receiverId).isEqualTo(receiverId)
        assertThat(result.status).isEqualTo(CallStatus.PENDING.code)
        verify(callRepository).save(any())
    }

    @Test
    fun `should throw CallSelfCallException when caller and receiver are the same`() {
        // given
        val userId = "user-A"

        // when & then
        assertThrows<CallSelfCallException> {
            callService.initiateCall(userId, userId)
        }
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw CallAlreadyActiveException when caller is already in an active call`() {
        // given
        val callerId = "user-A"
        val receiverId = "user-B"
        val activeCall = CallEntity(
            id = "call-existing",
            callerId = callerId,
            receiverId = "user-C",
            status = CallStatus.ACTIVE.code,
        )

        `when`(callRepository.findActiveCallByUserId(callerId, CallStatus.ACTIVE.code))
            .thenReturn(listOf(activeCall))

        // when & then
        assertThrows<CallAlreadyActiveException> {
            callService.initiateCall(callerId, receiverId)
        }
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw CallAlreadyActiveException when receiver is already in an active call`() {
        // given
        val callerId = "user-A"
        val receiverId = "user-B"
        val activeCall = CallEntity(
            id = "call-existing",
            callerId = "user-C",
            receiverId = receiverId,
            status = CallStatus.ACTIVE.code,
        )

        `when`(callRepository.findActiveCallByUserId(callerId, CallStatus.ACTIVE.code))
            .thenReturn(emptyList())
        `when`(callRepository.findActiveCallByUserId(receiverId, CallStatus.ACTIVE.code))
            .thenReturn(listOf(activeCall))

        // when & then
        assertThrows<CallAlreadyActiveException> {
            callService.initiateCall(callerId, receiverId)
        }
    }

    // ──────────────────────────────────────────────────────────────
    // acceptCall
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should transition call to ACTIVE when acceptCall is called by receiver`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val pendingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.PENDING.code,
        )
        val savedCall = pendingCall.apply {
            status = CallStatus.ACTIVE.code
            startedAt = LocalDateTime.now()
        }

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))
        `when`(callRepository.save(any())).thenReturn(savedCall)

        // when
        val result = callService.acceptCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ACTIVE.code)
        assertThat(result.startedAt).isNotNull
        verify(callRepository).save(pendingCall)
    }

    @Test
    fun `should throw CallUnauthorizedException when acceptCall is called by non-receiver`() {
        // given
        val callId = "call-1"
        val intruder = "user-X"
        val pendingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.PENDING.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))

        // when & then
        assertThrows<CallUnauthorizedException> {
            callService.acceptCall(callId, intruder)
        }
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw CallInvalidStatusTransitionException when acceptCall is called on ENDED call`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val endedCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.ENDED.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(endedCall))

        // when & then
        assertThrows<CallInvalidStatusTransitionException> {
            callService.acceptCall(callId, receiverId)
        }
    }

    @Test
    fun `should throw CallInvalidStatusTransitionException when acceptCall is called on DECLINED call`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val declinedCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.DECLINED.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(declinedCall))

        // when & then
        assertThrows<CallInvalidStatusTransitionException> {
            callService.acceptCall(callId, receiverId)
        }
    }

    // ──────────────────────────────────────────────────────────────
    // declineCall
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should transition call to DECLINED when declineCall is called by receiver`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val pendingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.PENDING.code,
        )
        val savedCall = pendingCall.apply { status = CallStatus.DECLINED.code }

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))
        `when`(callRepository.save(any())).thenReturn(savedCall)

        // when
        val result = callService.declineCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.DECLINED.code)
    }

    @Test
    fun `should throw CallUnauthorizedException when declineCall is called by non-receiver`() {
        // given
        val callId = "call-1"
        val intruder = "user-X"
        val pendingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.PENDING.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))

        // when & then
        assertThrows<CallUnauthorizedException> {
            callService.declineCall(callId, intruder)
        }
    }

    @Test
    fun `should throw CallInvalidStatusTransitionException when declineCall is called on already ACTIVE call`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val activeCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.ACTIVE.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))

        // when & then
        assertThrows<CallInvalidStatusTransitionException> {
            callService.declineCall(callId, receiverId)
        }
    }

    // ──────────────────────────────────────────────────────────────
    // endCall
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should transition call to ENDED and record durationSeconds when endCall is called by caller`() {
        // given
        val callId = "call-1"
        val callerId = "user-A"
        val startTime = LocalDateTime.now().minusMinutes(5)
        val activeCall = CallEntity(
            id = callId,
            callerId = callerId,
            receiverId = "user-B",
            status = CallStatus.ACTIVE.code,
            startedAt = startTime,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))
        `when`(callRepository.save(any())).thenAnswer { it.arguments[0] }

        // when
        val result = callService.endCall(callId, callerId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ENDED.code)
        assertThat(result.endedAt).isNotNull
        assertThat(result.durationSeconds).isGreaterThan(0L)
        assertThat(result.durationSeconds).isCloseTo(300L, org.assertj.core.data.Offset.offset(5L))
    }

    @Test
    fun `should transition call to ENDED when endCall is called by receiver`() {
        // given
        val callId = "call-1"
        val receiverId = "user-B"
        val activeCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = receiverId,
            status = CallStatus.ACTIVE.code,
            startedAt = LocalDateTime.now().minusSeconds(30),
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))
        `when`(callRepository.save(any())).thenAnswer { it.arguments[0] }

        // when
        val result = callService.endCall(callId, receiverId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.ENDED.code)
    }

    @Test
    fun `should set durationSeconds to 0 when startedAt is null on endCall`() {
        // given: startedAt이 null인 비정상 상태 (버그 방어)
        val callId = "call-1"
        val callerId = "user-A"
        val activeCallWithoutStartedAt = CallEntity(
            id = callId,
            callerId = callerId,
            receiverId = "user-B",
            status = CallStatus.ACTIVE.code,
            startedAt = null,  // 비정상: startedAt 없이 ACTIVE
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCallWithoutStartedAt))
        `when`(callRepository.save(any())).thenAnswer { it.arguments[0] }

        // when
        val result = callService.endCall(callId, callerId)

        // then
        assertThat(result.durationSeconds).isEqualTo(0L)
        assertThat(result.status).isEqualTo(CallStatus.ENDED.code)
    }

    @Test
    fun `should throw CallUnauthorizedException when endCall is called by outsider`() {
        // given
        val callId = "call-1"
        val outsider = "user-X"
        val activeCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.ACTIVE.code,
            startedAt = LocalDateTime.now().minusSeconds(10),
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))

        // when & then
        assertThrows<CallUnauthorizedException> {
            callService.endCall(callId, outsider)
        }
    }

    @Test
    fun `should throw CallInvalidStatusTransitionException when endCall is called on PENDING call`() {
        // given
        val callId = "call-1"
        val callerId = "user-A"
        val pendingCall = CallEntity(
            id = callId,
            callerId = callerId,
            receiverId = "user-B",
            status = CallStatus.PENDING.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))

        // when & then
        assertThrows<CallInvalidStatusTransitionException> {
            callService.endCall(callId, callerId)
        }
    }

    @Test
    fun `should throw CallInvalidStatusTransitionException when endCall is called on already ENDED call`() {
        // given
        val callId = "call-1"
        val callerId = "user-A"
        val endedCall = CallEntity(
            id = callId,
            callerId = callerId,
            receiverId = "user-B",
            status = CallStatus.ENDED.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(endedCall))

        // when & then
        assertThrows<CallInvalidStatusTransitionException> {
            callService.endCall(callId, callerId)
        }
    }

    // ──────────────────────────────────────────────────────────────
    // markAsMissed
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should transition call to MISSED when markAsMissed is called on PENDING call`() {
        // given
        val callId = "call-1"
        val pendingCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.PENDING.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(pendingCall))
        `when`(callRepository.save(any())).thenAnswer { it.arguments[0] }

        // when
        val result = callService.markAsMissed(callId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.MISSED.code)
    }

    @Test
    fun `should throw CallInvalidStatusTransitionException when markAsMissed is called on ACTIVE call`() {
        // given
        val callId = "call-1"
        val activeCall = CallEntity(
            id = callId,
            callerId = "user-A",
            receiverId = "user-B",
            status = CallStatus.ACTIVE.code,
        )

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(activeCall))

        // when & then
        assertThrows<CallInvalidStatusTransitionException> {
            callService.markAsMissed(callId)
        }
    }

    // ──────────────────────────────────────────────────────────────
    // getCall
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should return call when getCall is called with valid callId`() {
        // given
        val callId = "call-1"
        val call = CallEntity(id = callId, callerId = "user-A", receiverId = "user-B")

        `when`(callRepository.findById(callId)).thenReturn(Optional.of(call))

        // when
        val result = callService.getCall(callId)

        // then
        assertThat(result.id).isEqualTo(callId)
        verify(callRepository).findById(callId)
    }

    @Test
    fun `should throw CallNotFoundException when getCall is called with invalid callId`() {
        // given
        val invalidCallId = "non-existent"
        `when`(callRepository.findById(invalidCallId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<CallNotFoundException> {
            callService.getCall(invalidCallId)
        }
    }

    // ──────────────────────────────────────────────────────────────
    // getCallHistory
    // ──────────────────────────────────────────────────────────────

    @Test
    fun `should return call history when getCallHistory is called with valid userId`() {
        // given
        val userId = "user-A"
        val calls = listOf(
            CallEntity(id = "call-1", callerId = userId, receiverId = "user-B"),
            CallEntity(id = "call-2", callerId = "user-C", receiverId = userId),
        )

        `when`(callRepository.findByCallerIdOrReceiverId(userId, userId)).thenReturn(calls)

        // when
        val result = callService.getCallHistory(userId)

        // then
        assertThat(result).hasSize(2)
        verify(callRepository).findByCallerIdOrReceiverId(userId, userId)
    }

    @Test
    fun `should return empty list when getCallHistory has no records`() {
        // given
        val userId = "user-new"
        `when`(callRepository.findByCallerIdOrReceiverId(userId, userId)).thenReturn(emptyList())

        // when
        val result = callService.getCallHistory(userId)

        // then
        assertThat(result).isEmpty()
    }
}
