package com.maum.backend.entity.call

import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.params.ParameterizedTest
import org.junit.jupiter.params.provider.CsvSource

class CallStatusTest {

    @ParameterizedTest(name = "code={0} → {1}")
    @CsvSource(
        "0, PENDING",
        "1, ACTIVE",
        "2, ENDED",
        "3, DECLINED",
        "4, MISSED",
    )
    fun `should return correct CallStatus from valid code`(code: Int, expectedName: String) {
        // when
        val status = CallStatus.fromCode(code)

        // then
        assertThat(status.name).isEqualTo(expectedName)
    }

    @Test
    fun `should throw IllegalArgumentException when fromCode receives unknown code`() {
        // when & then
        assertThrows<IllegalArgumentException> {
            CallStatus.fromCode(99)
        }
    }

    @Test
    fun `should throw IllegalArgumentException when fromCode receives negative code`() {
        // when & then
        assertThrows<IllegalArgumentException> {
            CallStatus.fromCode(-1)
        }
    }

    @Test
    fun `should have correct code values for all statuses`() {
        assertThat(CallStatus.PENDING.code).isEqualTo(0)
        assertThat(CallStatus.ACTIVE.code).isEqualTo(1)
        assertThat(CallStatus.ENDED.code).isEqualTo(2)
        assertThat(CallStatus.DECLINED.code).isEqualTo(3)
        assertThat(CallStatus.MISSED.code).isEqualTo(4)
    }
}
